// Apollo.io API Key
const apiKey = $input.item.json.apolloApiKey || process.env.APOLLO_API_KEY || "K3j_5fBy6sc4wXQ-At1Z7A";

// Search parameters
const searchParams = {
  "api_key": apiKey,
  "q_organization_domains": $input.item.json.domains || ["shopify.com", "square.com", "stripe.com"],
  "page": 1,
  "person_titles": ["Marketing", "CMO", "Growth", "Performance", "Digital"],
  "person_seniorities": ["director", "executive", "vp", "owner"],
  "contact_available": true,
  "num_results": 5
};

// Construct the API request
const options = {
  method: 'POST',
  url: 'https://api.apollo.io/v1/mixed_people/search',
  headers: {
    'Content-Type': 'application/json',
    'Cache-Control': 'no-cache'
  },
  body: JSON.stringify(searchParams)
};

return {
  options: options,
  searchParams: searchParams,
  apiKey: apiKey
};

// Transform Apollo API response to Airtable format
const people = $input.item.json.people || [];

// Format for Airtable
const airtableRecords = people.map(person => {
  return {
    "fields": {
      "Name": person.name || "",
      "Email": person.email || "",
      "Title": person.title || "",
      "Company": person.organization_name || "",
      "LinkedIn": person.linkedin_url || "",
      "Phone": person.phone_number || "",
      "Industry": person.organization_industry || "",
      "Source": "Apollo.io",
      "Status": "New Lead",
      "Notes": `Found via Apollo.io search on ${new Date().toISOString().split('T')[0]}`
    }
  };
});

// Data for Klaviyo profiles too
const klaviyoProfiles = people.map(person => {
  return {
    "type": "profile",
    "attributes": {
      "email": person.email || "",
      "first_name": person.name ? person.name.split(' ')[0] : "",
      "last_name": person.name ? person.name.split(' ').slice(1).join(' ') : "",
      "title": person.title || "",
      "company": person.organization_name || "",
      "phone_number": person.phone_number || "",
      "properties": {
        "linkedin_url": person.linkedin_url || "",
        "industry": person.organization_industry || "",
        "source": "Apollo.io"
      }
    }
  };
});

return {
  airtableRecords: airtableRecords,
  klaviyoProfiles: klaviyoProfiles,
  peopleCount: people.length,
  rawData: people
};

// Final Results Summary
const airtableResult = $inputs.Airtable?.item?.json || { records: [] };
const klaviyoResult = $inputs.Klaviyo?.item?.json || { data: [] };
const leadsFound = $inputs.item.json.peopleCount || 0;

let summaryText = `# 🚀 Marketing Workflow Results\n\n`;
summaryText += `**Leads Found**: ${leadsFound}\n`;
summaryText += `**Airtable Records Created**: ${airtableResult.records?.length || 0}\n`;
summaryText += `**Klaviyo Profiles Created**: ${klaviyoResult.data?.length || 0}\n\n`;

summaryText += `## 📋 Lead Details\n\n`;

$inputs.item.json.rawData.forEach((person, index) => {
  summaryText += `### ${index + 1}. ${person.name || 'Unknown'}\n`;
  summaryText += `- **Title**: ${person.title || 'Unknown'}\n`;
  summaryText += `- **Company**: ${person.organization_name || 'Unknown'}\n`;
  summaryText += `- **Email**: ${person.email || 'Unknown'}\n`;
  summaryText += `- **Phone**: ${person.phone_number || 'Unknown'}\n`;
  summaryText += `- **Industry**: ${person.organization_industry || 'Unknown'}\n\n`;
});

summaryText += `\n## 🔄 Workflow Details\n\n`;
summaryText += `- **Date**: ${new Date().toISOString()}\n`;
summaryText += `- **Source**: Apollo.io\n`;
summaryText += `- **Destinations**: Airtable, Klaviyo\n`;

return {
  summaryText: summaryText,
  markdownSummary: summaryText,
  execTime: new Date().toISOString(),
  stats: {
    leadsFound: leadsFound,
    airtableRecords: airtableResult.records?.length || 0,
    klaviyoProfiles: klaviyoResult.data?.length || 0
  }
};
